+#[test]
+fn deep_all_eight_attribute_combinations() {
+    let mut algebra = ShapeTransitionAlgebra::new();
+    let root = algebra.root_shape_id();
+    let mut current = root;
+
+    let combos: Vec<PropertyAttributes> = vec![
+        PropertyAttributes {
+            writable: false,
+            enumerable: false,
+            configurable: false,
+        },
+        PropertyAttributes {
+            writable: false,
+            enumerable: false,
+            configurable: true,
+        },
+        PropertyAttributes {
+            writable: false,
+            enumerable: true,
+            configurable: false,
+        },
+        PropertyAttributes {
+            writable: false,
+            enumerable: true,
+            configurable: true,
+        },
+        PropertyAttributes {
+            writable: true,
+            enumerable: false,
+            configurable: false,
+        },
+        PropertyAttributes {
+            writable: true,
+            enumerable: false,
+            configurable: true,
+        },
+        PropertyAttributes {
+            writable: true,
+            enumerable: true,
+            configurable: false,
+        },
+        PropertyAttributes {
+            writable: true,
+            enumerable: true,
+            configurable: true,
+        },
+    ];
+
+    for (i, attrs) in combos.iter().enumerate() {
+        let key = format!("prop_{i}");
+        let outcome = algebra
+            .apply_mutation(
+                current,
+                ShapeMutation::AddProperty {
+                    key: key.clone(),
+                    attributes: *attrs,
+                },
+            )
+            .unwrap();
+        let desc = outcome
+            .shape
+            .property_layout
+            .iter()
+            .find(|d| d.property_key == key)
+            .unwrap();
+        assert_eq!(desc.attributes, *attrs);
+        current = outcome.shape.shape_id;
+    }
+
+    let final_shape = algebra.shape(current).unwrap();
+    assert_eq!(final_shape.property_count(), 8);
+}
